// This is a Higher-Order Function
fun runTwice(action: () -> Unit) {
    println("Running first time...")
    action() // We execute the passed-in logic
    println("Running second time...")
    action() // We execute it again!
}

fun main() {
    // We pass our Lambda logic directly in!
    runTwice({ println("Boom!") })
}
